1	package com.fortinet.nac.ingestion.delayqueue;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.JsonUtil;
6	
7	import lombok.RequiredArgsConstructor;
8	import org.redisson.api.RScoredSortedSet;
9	import org.redisson.api.RedissonClient;
10	import org.springframework.stereotype.Component;
11	
12	@Component
13	@RequiredArgsConstructor
14	public class RedisDelayQueueUtil {
15	
16	    private final RedissonClient redissonClient;
17	    private final JsonUtil jsonUtil;
18	
19	    public void enqueueWithDelay(IngestionRequest req, long delayMillis) {
20	        long fireTime = System.currentTimeMillis() + delayMillis;
21	        RScoredSortedSet<String> sortedSet = redissonClient.getScoredSortedSet(Constants.RedisKeys.INGESTION_DELAY_QUEUE);
22	        sortedSet.add(fireTime, jsonUtil.toJson(req));
23	    }
24	}
