11	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
12	import com.fortinet.nac.ingestion.entity.Entity;
13	import com.fortinet.nac.ingestion.service.EntityService;
14	import com.fortinet.nac.ingestion.util.EntityCache;
15	import com.fortinet.nac.ingestion.util.RedisUtil;
16	
17	import lombok.RequiredArgsConstructor;
18	import lombok.extern.slf4j.Slf4j;
19	
20	import org.springframework.stereotype.Component;
21	
22	import java.time.Instant;
23	
24	/**
25	 * Handles the case where an entity exists in cache but the incoming request
26	 * carries a different device type (e.g., HOST → USER_HOST_BINDING).
27	 *
28	 * This typically happens when a host that was previously seen as a standalone
29	 * HOST is now observed with a user binding, promoting it to USER_HOST_BINDING.
30	 *
31	 * The handler invalidates the stale cache entry, updates the existing entity's
32	 * type and fingerprint, resets its processing stage, and re-runs the state machine.
33	 */
34	@Slf4j
35	@Component
36	@RequiredArgsConstructor
37	public class DeviceTypeChangedHandler {
38	
39	    private final EntityService entityService;
40	    private final EntityCache entityCache;
41	    private final DistributedLock distributedLock;
42	    private final EntityStateMachine stateMachine;
43	    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;
44	
45	    public StatusOr<Entity> handle(IngestionRequest req, Entity cachedEntity) {
46	        EntityType oldType = cachedEntity.getType();
47	        EntityType newType = EntityType.valueOf(req.getEntityType());
48	
49	        log.info("DeviceTypeChangedHandler: entityId={}, typeChange={} -> {}, reqId={}",
50	                cachedEntity.getId(), oldType, newType, req.getRequestId());
51	
52	        // 1. Acquire process lock — type change is a mutating operation
53	        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
54	        boolean acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
55	        if (!acquired) {
56	            log.warn("DeviceTypeChangedHandler: failed to acquire process lock, entityId={}, reqId={}",
57	                    cachedEntity.getId(), req.getRequestId());
58	            return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
59	                    "process lock busy during type change");
60	        }
61	
62	        try {
63	            // 2. Re-read from DB to avoid stale-cache races
64	            Entity dbEntity = entityService.getEntity(cachedEntity.getId());
65	            if (dbEntity == null) {
66	                log.error("DeviceTypeChangedHandler: entity disappeared from DB, entityId={}", cachedEntity.getId());
67	                return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR,
68	                        "entity not found in DB: " + cachedEntity.getId());
69	            }
70	
71	            // 3. Rebuild fingerprint for the new type
72	            FingerprintBuildResult fpResult = entityAttributeFingerprintBuilder.build(req);
73	            String newFp = fpResult.getFingerprint();
74	
75	            // 4. Update entity: type, fingerprint, reset processing state
76	            dbEntity.setType(newType);
77	            dbEntity.setAttributeFingerprint(newFp);
78	            dbEntity.setProcessingStage(EntityStage.PENDING.toString());
79	            dbEntity.setProcessingCode(0);
80	            dbEntity.setErrorMessage(null);
81	            dbEntity.setProcessingResult(null);
82	            dbEntity.setLastReqVersion(req.getVersion());
83	            dbEntity.setUpdatedAt(Instant.now());
84	
85	            // For USER_HOST_BINDING, populate userIdentity
86	            if (newType == EntityType.USER_HOST_BINDING) {
87	                dbEntity.setUserId(req.getUserId());
88	                dbEntity.setUserIdentity(req.getUserId());
89	            }
90	
91	            entityService.save(dbEntity);
92	            log.info("DeviceTypeChangedHandler: entity updated in DB, entityId={}, newType={}, newFp={}",
93	                    dbEntity.getId(), newType, newFp);
94	
95	            // 5. Invalidate old cache and write updated entity
96	            String existKey = RedisUtil.getExistKey(req);
97	            try {
98	                entityCache.cacheEntity(existKey, dbEntity, Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
99	            } catch (Exception ex) {
100	                log.warn("Failed to update cache after type change, entityId={}, err={}",
101	                        dbEntity.getId(), ex.toString());
102	            }
103	
104	            // 6. Re-run state machine from PENDING
105	            return stateMachine.start(req.getRequestId(), req.isAsync(), dbEntity);
106	
107	        } finally {
108	            distributedLock.unLock(processLockKey);
109	        }
110	    }
111	}
